using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---

var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// With the default reflection resolver every type resolves, so Person succeeds:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded – {info!.Type.Name}");
}

// Build options that use a *source-gen* context with only Person registered.
// Asking for an unregistered type (int[]) will return false instead of throwing.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = PersonOnlyContext.Default
};

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrayInfo))
{
    Console.WriteLine($"Unexpected: got metadata for int[] – {arrayInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int[]> returned false – no metadata (no exception thrown)");
}

// --- types ---

public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;

